    String deleteFileName( String filenames , String filename ){
        String[] fileNames = filenames.split("\\|",-1);
        List<String> newFileNames = new ArrayList<>();
        //從filenames裡面移除filename，剩下的filenames加入newFileNames裡面
        int idx ;
        for( idx = 0 ; idx < fileNames.length ; idx++ ){ //把filename前面的filenames加入newFileNames
            if( !filename.equals(fileNames[idx]) )
                newFileNames.add(fileNames[idx]);
            else
                break;
        }
        for( ++idx ; idx < fileNames.length ; idx++ ){ //把filename後面的filenames加入newFileNames
            newFileNames.add(fileNames[idx]);
        }

        return String.join("|",newFileNames);
    }

    String removePreCheck(CellInfo info , NUIForm form , int rootNodeId ){
        //檢查這個欄位是否唯讀
        if( info.getAttribute("ro") != null )return "ro";

        //檢查資料是否上鎖 以及 此欄位是否允許上鎖後編輯
        boolean dataLocked = "1".equals(new BDBSmartWorker(form.getApname()).getFieldValue(form.getRootDomainId(),rootNodeId, DConst.ENTRY_LOCKED));
        boolean fieldAllowEditAfterLocked = info.getAttribute("nolock") != null;
        if( !fieldAllowEditAfterLocked && dataLocked )return "locked";

        return "";
    }

